const svcs = [
  { name: 'n8n', url: 'http://localhost:5678' },
  { name: 'Hermes', url: 'http://localhost:32772' },
  { name: 'Ollama', url: 'http://localhost:3000' },
  { name: 'Paperclip', url: 'http://localhost:52309' },
  { name: 'Dashboard', url: 'http://localhost:3011' }
];
const r = [];
for (const s of svcs) {
  try {
    await this.helpers.httpRequest({ method: 'GET', url: s.url, timeout: 5000 });
    r.push({ name: s.name, status: 'online' });
  } catch(e) {
    r.push({ name: s.name, status: 'offline' });
  }
}
const online = r.filter(x => x.status === 'online').length;
const summary = r.map(x => (x.status === 'online' ? '✅ ' : '❌ ') + x.name).join(' | ');
return [{ json: { services: r, online, total: r.length, summary, ts: new Date().toISOString() } }];
